const TARGET_STATUS = 'Concluído';
const IDEMPOTENCY_MARK = 'A2.11 disparada em';
const pickTitle = (page) => {
  for (const prop of Object.values(page.properties || {})) {
    if (prop?.type === 'title') return (prop.title || []).map((item) => item.plain_text || '').join('').trim();
  }
  return '';
};
const pickSelect = (prop) => prop?.select?.name || '';
const pickPlainText = (prop) => (prop?.rich_text || []).map((item) => item.plain_text || '').join('');
const out = [];
for (const item of $input.all()) {
  const page = item.json || {};
  const props = page.properties || {};
  const status = pickSelect(props.Status);
  const observacoes_atual = pickPlainText(props['Observações']);
  if (status === TARGET_STATUS && !observacoes_atual.includes(IDEMPOTENCY_MARK) && !page.archived) {
    out.push({ json: { cliente_page_id: page.id, cliente_nome: pickTitle(page), cliente_status: status, observacoes_atual } });
  }
}
return out;

const CSAT_FORM_URL = '<CSAT_FORM_URL_redacted>';
const NPS_FORM_URL = '<NPS_FORM_URL_redacted>';
const OLAVO_PHONE = '<OLAVO_PHONE_redacted>';
const out = [];
for (const item of $input.all()) {
  const cliente = item.json || {};
  const cliente_page_id = cliente.cliente_page_id;
  const cliente_nome = cliente.cliente_nome || '';
  if (!cliente_page_id) {
    throw new Error('cliente_page_id ausente - nao montar CSAT/NPS sem cliente');
  }
  const encodedId = encodeURIComponent(cliente_page_id);
  const encodedName = encodeURIComponent(cliente_nome);
  const csat_link = `${CSAT_FORM_URL}#cliente=${encodedId}&cliente_nome=${encodedName}`;
  const nps_link = `${NPS_FORM_URL}#cliente=${encodedId}&cliente_nome=${encodedName}`;
  const text = `[Onb A2.11] Disparar CSAT/NPS para cliente ${cliente_nome}
CSAT: ${csat_link}
NPS: ${nps_link}
ID do cliente=${cliente_page_id}
Acao: enviar os 2 links ao cliente off-platform.`;
  out.push({ json: { ...cliente, number: OLAVO_PHONE, csat_link, nps_link, text } });
}
return out;

const mensagens = $('[Onb A2.11] Montar Mensagem e Links').all().map((item) => item.json);
const responses = $input.all();
const now = new Date();
const brTimestamp = now.toLocaleString('sv-SE', { timeZone: 'America/Sao_Paulo' }).replace(' ', 'T') + '-03:00';
const out = [];
for (const [index, responseItem] of responses.entries()) {
  const msg = mensagens[index];
  if (!msg) continue;
  const payload = responseItem.json || {};
  const statusCode = Number(payload.statusCode || payload.response?.statusCode || 0);
  const failed = Boolean(payload.error || payload.message || (statusCode && (statusCode < 200 || statusCode >= 300)));
  const evolutionStatus = failed ? 'falhou' : 'ok';
  const detail = statusCode ? `HTTP ${statusCode}` : (failed ? 'erro sem status HTTP' : '');
  const linhaNova = `A2.11 disparada em ${brTimestamp}. CSAT: ${msg.csat_link}, NPS: ${msg.nps_link}. Status Evolution: ${evolutionStatus}${detail ? ` (${detail})` : ''}.`;
  const observacoes_atual = msg.observacoes_atual || '';
  const observacoes_finais = observacoes_atual ? `${observacoes_atual}\n${linhaNova}` : linhaNova;
  out.push({ json: { ...msg, evolution_status: evolutionStatus, evolution_detail: detail, linha_nova: linhaNova, observacoes_finais } });
}
return out;
